mapper.select:
SELECT OBJECT_NAME AS objectName /* object명 */ , OWNER AS owner /* 소유자 */ , OBJECT_TYPE AS objectType /* object타입 */ , TO_CHAR(CREATED, 'YYYY-MM-DD HH24:MI:SS') AS created /* 최초등록일 */ , TO_CHAR(LAST_DDL_TIME, 'YYYY-MM-DD HH24:MI:SS') AS lastDdlTime /* 수정일 */ , TO_CHAR(REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS regstDttm /* 등록일 */ FROM CMN_USER_OBJECT_HST
AND UPPER(OBJECT_NAME) LIKE '%' || UPPER(#{pObjName}) || '%'
AND TO_CHAR(LAST_DDL_TIME,'YYYYMMDD') BETWEEN #{pSearchStartDt} AND #{pSearchEndDt}
AND TO_CHAR(REGST_DTTM,'YYYYMMDD') BETWEEN #{pSearchStartDt} AND #{pSearchEndDt}
AND OWNER = #{pOwner}
AND OBJECT_TYPE LIKE #{pObjType} || '%'
GROUP BY OBJECT_NAME,OWNER,OBJECT_ID,OBJECT_TYPE,CREATED,LAST_DDL_TIME,REGST_ID,REGST_DTTM ORDER BY LAST_DDL_TIME DESC, REGST_DTTM DESC

SELECT OBJECT_NAME AS objectName
	   , SOURCE_TEXT AS sourceText
  FROM CMN_USER_OBJECT_HST
 WHERE OBJECT_NAME = #{objectName}
   AND TO_CHAR(LAST_DDL_TIME,'YYYY-MM-DD HH24:MI:SS') = #{lastDdlTime}
ORDER BY LAST_DDL_TIME, TO_NUMBER(SOURCE_LINE)
